// ============================================================
// NÓ DE CÓDIGO — Análise de Sentimentos por Palavras-Chave
// Método escolhido: classificação léxica (sem API externa)
// Vantagem: gratuito, sem latência de rede, sem dependência externa
// Limitação: não capta ironia, contexto complexo ou linguagem informal
// ============================================================

const texto = $input.first().json.body?.texto || $input.first().json.texto || '';

if (!texto || texto.trim() === '') {
  return [{
    json: {
      erro: 'Nenhum texto recebido.',
      instrucao: 'Envie um POST com o campo "texto" no body JSON.'
    }
  }];
}

const textoNormalizado = texto.toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')  // remove acentos
  .replace(/[^a-z0-9\s]/g, ' ');    // remove pontuação

const palavras = textoNormalizado.split(/\s+/).filter(p => p.length > 1);

// ---- Léxico de palavras positivas ----
const positivas = new Set([
  'otimo', 'excelente', 'incrivel', 'fantastico', 'maravilhoso', 'perfeito',
  'adorei', 'amei', 'gostei', 'gosto', 'feliz', 'felicidade', 'satisfeito',
  'satisfacao', 'alegre', 'alegria', 'bom', 'boa', 'bons', 'boas', 'util',
  'eficiente', 'rapido', 'facil', 'simples', 'recomendo', 'recomendaria',
  'aprovei', 'aprovado', 'funciona', 'funcionou', 'resolveu', 'ajudou',
  'ajuda', 'economizei', 'ganho', 'ganhos', 'lucro', 'crescimento',
  'melhorou', 'melhor', 'top', 'show', 'parabens', 'obrigado', 'obrigada',
  'sucesso', 'positivo', 'positiva', 'certo', 'certa', 'correto', 'grato',
  'grata', 'agradecido', 'agradecida', 'encantado', 'encantada', 'surpreso',
  'surpreendido', 'surpresa', 'impressionante', 'produtivo', 'produtividade'
]);

// ---- Léxico de palavras negativas ----
const negativas = new Set([
  'pessimo', 'terrivel', 'horrivel', 'ruim', 'mal', 'mau', 'problema',
  'problemas', 'erro', 'erros', 'falha', 'falhou', 'nao', 'nunca', 'jamais',
  'odiei', 'odeio', 'detestei', 'detesto', 'insatisfeito', 'insatisfacao',
  'frustrado', 'frustrada', 'frustrante', 'frustracao', 'triste', 'tristeza',
  'decepcionado', 'decepcionante', 'decepcao', 'lento', 'lenta', 'dificil',
  'complicado', 'travou', 'travando', 'bug', 'bugs', 'quebrado', 'quebrada',
  'defeito', 'defeituoso', 'pior', 'pessima', 'horrores', 'catastrofico',
  'caiu', 'caindo', 'perdido', 'perdi', 'cancelei', 'cancelamento', 'prejuizo',
  'perda', 'perdas', 'negativo', 'negativa', 'errado', 'errada', 'incorreto',
  'ineficiente', 'inutil', 'desapontado', 'desapontante', 'arrependido'
]);

// ---- Palavras de negação (invertem o próximo token) ----
const negacoes = new Set(['nao', 'nem', 'nunca', 'jamais', 'sem', 'nenhum', 'nenhuma']);

// ---- Contagem ponderada ----
let scorePOS = 0;
let scoreNEG = 0;
const palavrasPositivasDetectadas = [];
const palavrasNegativasDetectadas = [];

for (let i = 0; i < palavras.length; i++) {
  const palavra = palavras[i];
  const negado = i > 0 && negacoes.has(palavras[i - 1]);

  if (positivas.has(palavra)) {
    if (negado) {
      scoreNEG += 1;
      palavrasNegativasDetectadas.push(`não_${palavra}`);
    } else {
      scorePOS += 1;
      palavrasPositivasDetectadas.push(palavra);
    }
  } else if (negativas.has(palavra)) {
    if (negado) {
      scorePOS += 0.5; // negação de negativo = leve positivo
      palavrasPositivasDetectadas.push(`não_${palavra}`);
    } else {
      scoreNEG += 1;
      palavrasNegativasDetectadas.push(palavra);
    }
  }
}

// ---- Classificação final ----
let sentimento;
let confianca;
const diferenca = scorePOS - scoreNEG;
const totalTokens = scorePOS + scoreNEG;

if (totalTokens === 0) {
  sentimento = 'Neutro';
  confianca = 'Baixa';
} else if (diferenca > 0) {
  sentimento = 'Positivo';
  confianca = diferenca >= 2 ? 'Alta' : 'Media';
} else if (diferenca < 0) {
  sentimento = 'Negativo';
  confianca = Math.abs(diferenca) >= 2 ? 'Alta' : 'Media';
} else {
  sentimento = 'Neutro';
  confianca = 'Media';
}

const resultado = {
  sentimento,
  confianca,
  texto_original: texto,
  scores: {
    positivo: scorePOS,
    negativo: scoreNEG,
    balanco: diferenca
  },
  tokens_analisados: palavras.length,
  palavras_positivas_detectadas: palavrasPositivasDetectadas,
  palavras_negativas_detectadas: palavrasNegativasDetectadas,
  metodo: 'classificacao_lexica_palavras_chave',
  timestamp: new Date().toISOString()
};

return [{ json: resultado }];

// Prepara registro estruturado para sentimento POSITIVO
const d = $input.first().json;
return [{
  json: {
    acao: 'REGISTRO_POSITIVO',
    mensagem: `✅ Sentimento Positivo detectado com confiança ${d.confianca}.`,
    texto: d.texto_original,
    score_positivo: d.scores.positivo,
    score_negativo: d.scores.negativo,
    palavras_chave: d.palavras_positivas_detectadas,
    timestamp: d.timestamp,
    proximo_passo: 'Adicionar aba POSITIVOS na planilha / enviar e-mail de parabéns / registrar como elogio'
  }
}];

// Prepara registro estruturado para sentimento NEGATIVO
const d = $input.first().json;
return [{
  json: {
    acao: 'ALERTA_NEGATIVO',
    mensagem: `🚨 Sentimento Negativo detectado com confiança ${d.confianca}. Requer atenção imediata.`,
    texto: d.texto_original,
    score_positivo: d.scores.positivo,
    score_negativo: d.scores.negativo,
    palavras_chave: d.palavras_negativas_detectadas,
    timestamp: d.timestamp,
    proximo_passo: 'Adicionar aba NEGATIVOS na planilha / disparar e-mail de suporte / abrir ticket'
  }
}];

// Prepara registro estruturado para sentimento NEUTRO
const d = $input.first().json;
return [{
  json: {
    acao: 'REGISTRO_NEUTRO',
    mensagem: `⚪ Sentimento Neutro detectado. Texto sem carga emocional evidente.`,
    texto: d.texto_original,
    score_positivo: d.scores.positivo,
    score_negativo: d.scores.negativo,
    tokens_analisados: d.tokens_analisados,
    timestamp: d.timestamp,
    proximo_passo: 'Adicionar aba NEUTROS na planilha / revisar manualmente se necessário'
  }
}];

// Monta resposta HTTP final unificada
const entrada = $input.first().json;

const emojis = {
  'REGISTRO_POSITIVO': '✅',
  'ALERTA_NEGATIVO': '🚨',
  'REGISTRO_NEUTRO': '⚪'
};

return [{
  json: {
    status: 'ok',
    resultado: `Sentimento: ${entrada.acao?.includes('POSITIVO') ? 'Positivo' : entrada.acao?.includes('NEGATIVO') ? 'Negativo' : 'Neutro'}`,
    icone: emojis[entrada.acao] || '❓',
    mensagem: entrada.mensagem,
    acao_sugerida: entrada.proximo_passo,
    detalhes: {
      texto_analisado: entrada.texto,
      score_positivo: entrada.score_positivo,
      score_negativo: entrada.score_negativo,
      palavras_chave: entrada.palavras_chave || [],
      timestamp: entrada.timestamp
    },
    metodo: 'Classificação Léxica por Palavras-Chave (sem API externa)',
    limitacoes: [
      'Não detecta ironia ou sarcasmo',
      'Linguagem informal ou gírias podem não ser reconhecidas',
      'Contextos ambíguos podem resultar em classificação Neutra',
      'Léxico limitado ao vocabulário cadastrado'
    ]
  }
}];
